{
    public static partial class VerbDescriptions
    {
        public static partial class Regular
        {
            public static partial class Er
            {
                public const string Atteler = "Atteler est un verbe du premier groupe (-er) qui signifie mettre un animal de trait à un véhicule ou, par extension, associer ou mobiliser des moyens pour une action.";
                public const string Apaiser = "Apaiser est un verbe régulier du premier groupe (-er) qui signifie calmer, adoucir ou réduire une tension, une douleur ou un conflit. Il s'emploie aussi de façon pronominale (s'apaiser) pour exprimer le fait de se calmer.";
                public const string Approuver = "Approuver est un verbe régulier du premier groupe (-er) qui signifie exprimer son accord, juger favorablement une idée, une décision ou le comportement de quelqu'un.";
                public const string Acheter = "Acheter est un verbe courant qui exprime l'action d'acquérir quelque chose en échange d'argent. Il est très utilisé dans la vie quotidienne, notamment pour parler de courses, de biens et de services.";
                public const string Adapter = "Adapter est un verbe régulier du premier groupe (-er) qui signifie ajuster, modifier ou rendre quelque chose approprié à une situation, un usage ou un contexte donné.";
                public const string Aimer = "Aimer est un verbe régulier en -er qui exprime le sentiment d'affection, de goût ou de préférence. Très utilisé en français courant, il peut être suivi d'une personne, d'une chose ou d'une activité.";
                public const string Allumer = "Allumer est un verbe régulier du premier groupe (-er) qui signifie produire de la lumière, faire fonctionner une source lumineuse ou, par extension, susciter, éveiller un sentiment ou une réaction.";
                public const string Appeler = "Appeler est un verbe régulier en -er avec un changement orthographique : le 'l' se double pour certaines personnes afin de préserver le son [ɛ]. Il exprime l'action de nommer quelqu'un ou de téléphoner à quelqu'un.";
                public const string Arriver = "Arriver est un verbe régulier en -er qui signifie atteindre un lieu, venir ou se produire. En français, il se conjugue avec l'auxiliaire 'être' aux temps composés.";
                public const string Accrocher = "Accrocher est un verbe régulier du premier groupe (-er) qui signifie fixer quelque chose à un crochet, suspendre ou, par extension, attirer l'attention. Il peut s'employer de façon pronominale (s'accrocher) pour exprimer l'idée de se cramponner ou de persévérer.";
                public const string Annoncer = "Annoncer est un verbe régulier du premier groupe (-er) qui signifie faire connaître une information, communiquer une nouvelle ou prévenir de quelque chose. Il présente un changement orthographique : le 'c' prend une cédille (ç) devant 'a' et 'o' pour conserver le son [s].";
                public const string Actionner = "Actionner est un verbe régulier du premier groupe (-er) qui signifie mettre en marche un mécanisme, un appareil ou un dispositif en exerçant une action physique dessus.";
                public const string Axer = "Axer est un verbe régulier du premier groupe (-er) qui signifie orienter, organiser ou centrer quelque chose autour d'un thème, d'un objectif ou d'un axe principal. Il s'emploie aussi de façon pronominale (s'axer) pour indiquer que quelque chose est centré ou focalisé sur un élément particulier.";
                public const string Se_Axer = "S'axer est la forme pronominale réfléchie du verbe axer. Il signifie se centrer, se focaliser ou s'organiser autour d'un thème, d'un objectif ou d'un axe principal. Il exprime le fait que quelque chose — ou quelqu'un — s'oriente délibérément autour d'un point central.";
                public const string Aborder = "Aborder est un verbe régulier du premier groupe (-er) qui signifie s'approcher d'un lieu ou d'une personne, ou commencer à traiter un sujet. Il est très utilisé dans les contextes de navigation, de communication et d'interaction sociale.";
                public const string Attirer = "Attirer est un verbe régulier du premier groupe (-er) qui signifie exercer une force ou un charme qui fait venir vers soi. Il peut exprimer une attraction physique, une séduction ou un intérêt particulier pour quelque chose ou quelqu'un.";
                public const string Achever = "Achever est un verbe régulier du premier groupe (-er) qui signifie mener quelque chose à son terme, terminer complètement une action ou une œuvre. Il présente un changement de radical : le 'e' muet du radical devient 'è' devant une syllabe muette (j'achève, tu achèves).";
                public const string Se_Achever = "S'achever est la forme pronominale du verbe achever. Il signifie prendre fin, se terminer. Il se conjugue avec l'auxiliaire 'être' aux temps composés et exprime la conclusion naturelle d'un événement ou d'une période.";
            }
        }
    }
}
